// ❌ BAD - throw ex resets stack trace; origin of the bug is lost
try { ProcessPayment(order); }
catch (Exception ex) {
    _log.Error(ex);
    throw ex; // stack trace now points here, not at ProcessPayment
}

// ✅ GOOD - bare throw preserves the original stack trace
try { ProcessPayment(order); }
catch (Exception ex) {
    _log.Error(ex);
    throw; // original stack trace intact
}
// ✅ GOOD - wrap when adding context
try { ProcessPayment(order); }
catch (PaymentGatewayException ex) {
    throw new OrderException($"Order {order.Id} failed", ex); // inner exception
}

// ❌ BAD - const value baked into calling assemblies; changing 30 breaks callers without recompile
public const int SessionTimeoutMinutes = 30;

// ✅ GOOD - static readonly is read at runtime; all callers see the current value
public static readonly int SessionTimeoutMinutes = 30;
public static readonly DateTime ServiceStart = DateTime.UtcNow; // computed - impossible with const

// ✅ GOOD - readonly per instance: set once in constructor
public class OrderProcessor {
    public readonly string ProcessorId;
    public OrderProcessor(string id) => ProcessorId = id;
}

// ❌ BAD - First() throws if product not found; unhandled in a public API
public Product GetProduct(int id) =>
    _db.Products.First(p => p.Id == id); // throws if not found

// ✅ GOOD - FirstOrDefault signals absence; caller handles it cleanly
public Product? GetProduct(int id) {
    var product = _db.Products.FirstOrDefault(p => p.Id == id);
    if (product is null) throw new NotFoundException($"Product {id} not found");
    return product;
}
// Or: use SingleOrDefault when the Id column is unique
var order = _db.Orders.SingleOrDefault(o => o.Id == orderId);

// ❌ BAD - returns concrete List, exposing internal mutable collection to callers
public List<Product> GetFeatured() => _products;

// ✅ GOOD - return IReadOnlyList; caller can index without mutation access
public IReadOnlyList<Product> GetFeatured() => _products.AsReadOnly();

// ❌ BAD - IEnumerable.Count() on a large result set iterates the whole sequence
int count = products.Count(); // O(n) if IEnumerable, O(1) if ICollection

// ✅ GOOD - cast check or use Count property
if (products is ICollection<Product> col) { int n = col.Count; }

